  9→@Injectable()
 10→export class SessionService {
 11→	private readonly logger = new Logger(SessionService.name);
 12→	private readonly SESSION_TTL = 30 * 24 * 60 * 60;
 13→
 14→	constructor(
 15→		@Inject(REDIS_WRITE_CLIENT) private readonly redisWrite: Redis,
 16→		@Inject(REDIS_READ_CLIENT) private readonly redisRead: Redis,
 17→	) {}
 18→
 19→	async createSession({
 20→		session,
 21→		refreshToken,
 22→	}: {
 23→		session: ISession;
 24→		refreshToken: string;
 25→	}): Promise<void> {
 26→		this.logger.log('Creating session', {
 27→			userId: session.user_id,
 28→			sessionId: session.session_id,
 29→		});
 30→
 31→		const sessionKey = `session:${session.user_id}:${session.session_id}`;
 32→		const sessionSetKey = `sessions:${session.user_id}`;
 33→		const refreshKey = `refresh:${refreshToken}`;
 34→
 35→		const payload: IRefreshToken = {
 36→			user_id: session.user_id,
 37→			session_id: session.session_id,
 38→		};
 39→
 40→		await this.redisWrite
 41→			.multi()
 42→			.set(sessionKey, JSON.stringify(session), 'EX', this.SESSION_TTL)
 43→			.sadd(sessionSetKey, session.session_id)
 44→			.set(refreshKey, JSON.stringify(payload), 'EX', this.SESSION_TTL)
 45→			.exec();
 46→	}
 47→
 48→	async getSession({
 49→		userId,
 50→		sessionId,
 51→	}: {
 52→		userId: string;
 53→		sessionId: string;
 54→	}): Promise<ISession | null> {
 55→		this.logger.log('Getting session', { userId, sessionId });
 56→
 57→		const sessionKey = `session:${userId}:${sessionId}`;
 58→
 59→		let raw: string | null = null;
 60→
 61→		try {
 62→			raw = await this.redisRead.get(sessionKey);
 63→		} catch (error) {
 64→			this.logger.warn('Read replica failed, falling back to write client', {
 65→				userId,
 66→				sessionId,
 67→			});
 68→			raw = await this.redisWrite.get(sessionKey);
 69→		}
 70→
 71→		if (!raw) {
 72→			return null;
 73→		}
 74→
 75→		return JSON.parse(raw) as ISession;
 76→	}
 77→
 78→	async updateLastActive({
 79→		userId,
 80→		sessionId,
 81→	}: {
 82→		userId: string;
 83→		sessionId: string;
 84→	}): Promise<void> {
 85→		this.logger.log('Updating last active', { userId, sessionId });
 86→
 87→		const sessionKey = `session:${userId}:${sessionId}`;
 88→		const session = await this.getSession({ userId, sessionId });
 89→
 90→		if (!session) {
 91→			return;
 92→		}
 93→
 94→		session.last_active = new Date().toISOString();
 95→		await this.redisWrite.set(
 96→			sessionKey,
 97→			JSON.stringify(session),
 98→			'EX',
 99→			this.SESSION_TTL,
100→		);
101→	}
102→
103→	async destroySession({
104→		userId,
105→		sessionId,
106→		refreshToken,
107→	}: {
108→		userId: string;
109→		sessionId: string;
110→		refreshToken?: string;
111→	}): Promise<void> {
112→		this.logger.log('Destroying session', { userId, sessionId });
113→
114→		const sessionKey = `session:${userId}:${sessionId}`;
115→		const sessionSetKey = `sessions:${userId}`;
116→
117→		const multi = this.redisWrite.multi().del(sessionKey).srem(sessionSetKey, sessionId);
118→
119→		if (refreshToken) {
120→			multi.del(`refresh:${refreshToken}`);
121→		}
122→
123→		await multi.exec();
124→	}
125→
126→	async destroyAllSessions({ userId }: { userId: string }): Promise<void> {
127→		this.logger.log('Destroying all sessions', { userId });
128→
129→		const sessionSetKey = `sessions:${userId}`;
130→		let sessionIds: string[] = [];
131→
132→		try {
133→			sessionIds = await this.redisRead.smembers(sessionSetKey);
134→		} catch (error) {
135→			this.logger.warn('Read replica failed for smembers, falling back to write client', {
136→				userId,
137→			});
138→			sessionIds = await this.redisWrite.smembers(sessionSetKey);
139→		}
140→
141→		if (sessionIds.length === 0) {
142→			return;
143→		}
144→
145→		const multi = this.redisWrite.multi();
146→
147→		for (const sessionId of sessionIds) {
148→			multi.del(`session:${userId}:${sessionId}`);
149→		}
150→
151→		multi.del(sessionSetKey);
152→
153→		await multi.exec();
154→	}
155→
156→	async destroySessionsByCompanyId({
157→		userId,
158→		companyId,
159→	}: {
160→		userId: string;
161→		companyId: string;
162→	}): Promise<void> {
163→		this.logger.log('Destroying sessions by company id', { userId, companyId });
164→
165→		const sessionSetKey = `sessions:${userId}`;
166→		let sessionIds: string[] = [];
167→
168→		try {
169→			sessionIds = await this.redisRead.smembers(sessionSetKey);
170→		} catch (error) {
171→			this.logger.warn('Read replica failed for smembers, falling back to write client', {
172→				userId,
173→			});
174→			sessionIds = await this.redisWrite.smembers(sessionSetKey);
175→		}
176→
177→		const sessions = await Promise.all(
178→			sessionIds.map((sessionId) => this.getSession({ userId, sessionId })),
179→		);
180→
181→		const matchingSessions = sessions.filter(
182→			(session): session is ISession =>
183→				session !== null && session.company_id === companyId,
184→		);
185→
186→		for (const session of matchingSessions) {
187→			await this.destroySession({
188→				userId,
189→				sessionId: session.session_id,
190→			});
191→		}
192→	}
193→
194→	async validateRefreshToken({
195→		refreshToken,
196→	}: {
197→		refreshToken: string;
198→	}): Promise<IRefreshToken | null> {
199→		this.logger.log('Validating refresh token');
200→
201→		const refreshKey = `refresh:${refreshToken}`;
202→		let raw: string | null = null;
203→
204→		try {
205→			raw = await this.redisRead.get(refreshKey);
206→		} catch (error) {
207→			this.logger.warn('Read replica failed, falling back to write client');
208→			raw = await this.redisWrite.get(refreshKey);
209→		}
210→
211→		if (!raw) {
212→			return null;
213→		}
214→
215→		return JSON.parse(raw) as IRefreshToken;
216→	}
217→
218→	async rotateRefreshToken({
219→		oldToken,
220→		session,
221→	}: {
222→		oldToken: string;
223→		session: ISession;
224→	}): Promise<string> {
225→		this.logger.log('Rotating refresh token', {
226→			userId: session.user_id,
227→			sessionId: session.session_id,
228→		});
229→
230→		const tombstoneKey = `refresh_tombstone:${oldToken}`;
231→		const oldRefreshKey = `refresh:${oldToken}`;
232→		const newToken = randomUUID();
233→		const newRefreshKey = `refresh:${newToken}`;
234→
235→		const payload: IRefreshToken = {
236→			user_id: session.user_id,
237→			session_id: session.session_id,
238→		};
239→
240→		await this.redisWrite
241→			.multi()
242→			.del(oldRefreshKey)
243→			.set(tombstoneKey, JSON.stringify(payload), 'EX', 3600)
244→			.set(newRefreshKey, JSON.stringify(payload), 'EX', this.SESSION_TTL)
245→			.exec();
246→
247→		return newToken;
248→	}
249→
250→	async detectRefreshTokenReuse({
251→		refreshToken,
252→	}: {
253→		refreshToken: string;
254→	}): Promise<IRefreshToken | null> {
255→		this.logger.log('Detecting refresh token reuse');
256→
257→		const tombstoneKey = `refresh_tombstone:${refreshToken}`;
258→		let raw: string | null = null;
259→
260→		try {
261→			raw = await this.redisRead.get(tombstoneKey);
262→		} catch (error) {
263→			this.logger.warn('Read replica failed, falling back to write client');
264→			raw = await this.redisWrite.get(tombstoneKey);
265→		}
266→
267→		if (!raw) {
268→			return null;
269→		}
270→
271→		return JSON.parse(raw) as IRefreshToken;
272→	}
273→
274→	async updateCompanyContext({
275→		userId,
276→		sessionId,
277→		companyId,
278→		role,
279→	}: {
280→		userId: string;
281→		sessionId: string;
282→		companyId: string | null;
283→		role: 'admin' | 'member' | null;
284→	}): Promise<void> {
285→		this.logger.log('Updating company context', { userId, sessionId, companyId, role });
286→
287→		const sessionKey = `session:${userId}:${sessionId}`;
288→		const session = await this.getSession({ userId, sessionId });
289→
290→		if (!session) {
291→			return;
292→		}
293→
294→		session.company_id = companyId;
295→		session.role = role;
296→
297→		await this.redisWrite.set(
298→			sessionKey,
299→			JSON.stringify(session),
300→			'EX',
301→			this.SESSION_TTL,
302→		);
303→	}
304→}
