 98→	@Public()
 99→	@Post('token')
100→	@ApiOperation({ summary: 'Exchange auth code for JWT tokens' })
101→	@ApiResponse({
102→		status: HttpStatus.OK,
103→		description: 'Returns access token, sets refresh cookie',
104→	})
105→	async exchangeToken(
106→		@Body() dto: TokenExchangeDto,
107→		@Req() request: FastifyRequest,
108→		@Res() reply: FastifyReply,
109→	): Promise<void> {
110→		const result = await this.authService.exchangeCode({
111→			code: dto.code,
112→			ip: request.ip,
113→			userAgent: request.headers['user-agent'] ?? '',
114→			provider: 'github',
115→		});
116→
117→		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
118→			httpOnly: true,
119→			secure: !isDevEnv(),
120→			sameSite: 'strict',
121→			path: '/api/auth',
122→			maxAge: 30 * 24 * 60 * 60,
123→		});
124→
125→		reply.send({ access_token: result.accessToken });
126→	}
