128→	@Public()
129→	@Post('refresh')
130→	@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
131→	@ApiResponse({
132→		status: HttpStatus.OK,
133→		description: 'Returns new access token, rotates refresh cookie',
134→	})
135→	@ApiResponse({
136→		status: HttpStatus.UNAUTHORIZED,
137→		description: 'No or invalid refresh token',
138→	})
139→	async refresh(
140→		@Req() request: FastifyRequest,
141→		@Res() reply: FastifyReply,
142→	): Promise<void> {
143→		const refreshToken = (request.cookies as Record<string, string>)[
144→			REFRESH_TOKEN_COOKIE_NAME
145→		];
146→		if (!refreshToken) throw new UnauthorizedException('No refresh token');
147→
148→		const result = await this.authService.refreshTokens({ refreshToken });
149→
150→		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
151→			httpOnly: true,
152→			secure: !isDevEnv(),
153→			sameSite: 'strict',
154→			path: '/api/auth',
155→			maxAge: 30 * 24 * 60 * 60,
156→		});
157→
158→		reply.send({ access_token: result.accessToken });
159→	}
