import { IsNotEmpty, IsString } from 'class-validator';

export class SwitchCompanyDto {
	@IsString()
	@IsNotEmpty()
	company_id: string;
}

import {
	Body,
	Controller,
	ForbiddenException,
	Get,
	HttpStatus,
	Post,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';

import { CurrentUser } from '@modules/auth/decorators/current-user.decorator';
import { IRequestUser } from '@modules/auth/types/auth.interface';
import { CompanyMemberService } from '@modules/company-member/company-member.service';
import { ICompanyMemberBase } from '@modules/company-member/types/company-member.base.interface';
import { SessionService } from '@modules/session/session.service';
import { SwitchCompanyDto } from '@modules/user/dto/switch-company.dto';
import { IUserBase } from '@modules/user/types/user.base.interface';
import { UserService } from '@modules/user/user.service';

@ApiTags('Users')
@Controller('users')
export class UserController {
	constructor(
		private readonly userService: UserService,
		private readonly companyMemberService: CompanyMemberService,
		private readonly sessionService: SessionService,
	) {}

	@Get('me')
	@ApiOperation({ summary: 'Get current user profile with memberships' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Returns user profile and memberships' })
	@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Unauthorized' })
	async getMe(
		@CurrentUser() user: IRequestUser,
	): Promise<{ user: IUserBase | null; memberships: ICompanyMemberBase[] }> {
		const [foundUser, memberships] = await Promise.all([
			this.userService.findById({ userId: user.user_id }),
			this.companyMemberService.findByUserId({ userId: user.user_id }),
		]);

		return { user: foundUser, memberships };
	}

	@Post('me/company')
	@ApiOperation({ summary: 'Switch active company context' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Company context updated successfully' })
	@ApiResponse({ status: HttpStatus.FORBIDDEN, description: 'Not a member of the company' })
	@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Unauthorized' })
	async switchCompany(
		@Body() dto: SwitchCompanyDto,
		@CurrentUser() user: IRequestUser,
	): Promise<{ success: boolean }> {
		const membership = await this.companyMemberService.findByUserAndCompany({
			userId: user.user_id,
			companyId: dto.company_id,
		});

		if (!membership) {
			throw new ForbiddenException('Not a member of this company');
		}

		await this.sessionService.updateCompanyContext({
			userId: user.user_id,
			sessionId: user.session_id,
			companyId: dto.company_id,
			role: membership.role,
		});

		return { success: true };
	}
}

