const mockUserService = {
	findById: jest.fn(),
};

const mockCompanyMemberService = {
	findByUserId: jest.fn(),
	findByUserAndCompany: jest.fn(),
};

const mockSessionService = {
	updateCompanyContext: jest.fn(),
};

const mockUser: IRequestUser = {
	user_id: 'user-123',
	session_id: 'session-456',
	role: 'admin',
	company_id: 'company-abc',
};

const mockUserBase: IUserBase = {
	_id: 'user-123',
	email: 'test@example.com',
	name: 'Test User',
	avatar_url: null,
	last_login_at: null,
	created_at: new Date('2025-01-01'),
	updated_at: new Date('2025-01-01'),
	deleted_at: null,
};

const mockMembership: ICompanyMemberBase = {
	_id: 'member-789',
	user_id: 'user-123',
	company_id: 'company-abc',
	role: 'admin',
	created_at: new Date('2025-01-01'),
	updated_at: new Date('2025-01-01'),
	deleted_at: null,
};

describe('UserController', () => {
	let controller: UserController;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			controllers: [UserController],
			providers: [
				{ provide: UserService, useValue: mockUserService },
				{ provide: CompanyMemberService, useValue: mockCompanyMemberService },
				{ provide: SessionService, useValue: mockSessionService },
			],
		}).compile();

		controller = module.get<UserController>(UserController);
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(controller).toBeDefined();
	});

	describe('getMe', () => {
		it('should return user profile and memberships', async () => {
			const memberships = [mockMembership];
			mockUserService.findById.mockResolvedValue(mockUserBase);
			mockCompanyMemberService.findByUserId.mockResolvedValue(memberships);

			const result = await controller.getMe(mockUser);

			expect(mockUserService.findById).toHaveBeenCalledWith({ userId: 'user-123' });
			expect(mockCompanyMemberService.findByUserId).toHaveBeenCalledWith({
				userId: 'user-123',
			});
			expect(result).toEqual({ user: mockUserBase, memberships });
		});

		it('should return null user when not found', async () => {
			mockUserService.findById.mockResolvedValue(null);
			mockCompanyMemberService.findByUserId.mockResolvedValue([]);

			const result = await controller.getMe(mockUser);

			expect(result).toEqual({ user: null, memberships: [] });
		});
	});

	describe('switchCompany', () => {
		it('should update session and return success when user is a member', async () => {
			const dto: SwitchCompanyDto = { company_id: 'company-abc' };
			mockCompanyMemberService.findByUserAndCompany.mockResolvedValue(mockMembership);
			mockSessionService.updateCompanyContext.mockResolvedValue(undefined);

			const result = await controller.switchCompany(dto, mockUser);

			expect(mockCompanyMemberService.findByUserAndCompany).toHaveBeenCalledWith({
				userId: 'user-123',
				companyId: 'company-abc',
			});
			expect(mockSessionService.updateCompanyContext).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
				companyId: 'company-abc',
				role: 'admin',
			});
			expect(result).toEqual({ success: true });
		});

		it('should throw ForbiddenException when user is not a member', async () => {
			const dto: SwitchCompanyDto = { company_id: 'company-xyz' };
			mockCompanyMemberService.findByUserAndCompany.mockResolvedValue(null);

			await expect(controller.switchCompany(dto, mockUser)).rejects.toThrow(
				ForbiddenException,
			);

			expect(mockSessionService.updateCompanyContext).not.toHaveBeenCalled();
		});
	});
});
